const crypto = require('crypto');
const MAX_TIMESTAMP_SKEW_SEC = 300;
const VALID_ACTIONS = new Set(['approve','fix','manual']);

const item = $input.first() ?? {};
const jsonPart = item.json ?? {};
const binaryPart = item.binary ?? {};
const headers = jsonPart.headers ?? {};

let rawBody = '';
if (binaryPart.data) {
  const d = binaryPart.data;
  if (Buffer.isBuffer(d)) rawBody = d.toString('utf8');
  else if (typeof d === 'string') rawBody = Buffer.from(d, 'base64').toString('utf8');
  else if (d.data) rawBody = Buffer.isBuffer(d.data) ? d.data.toString('utf8') : Buffer.from(d.data, 'base64').toString('utf8');
}
if (!rawBody && typeof jsonPart.body === 'string') rawBody = jsonPart.body;
if (!rawBody && jsonPart.body) rawBody = JSON.stringify(jsonPart.body);

let body = {};
try { body = JSON.parse(rawBody || '{}'); } catch (e) {}

const signature = headers['x-signature-ed25519'] ?? '';
const timestamp = headers['x-signature-timestamp'] ?? '';
const publicKey = $env.DISCORD_PUBLIC_KEY ?? '';

// Replay-Schutz: Timestamp darf nicht mehr als 5min vom Server abweichen
const tsNum = parseInt(timestamp, 10);
const nowSec = Math.floor(Date.now() / 1000);
if (!Number.isFinite(tsNum) || Math.abs(nowSec - tsNum) > MAX_TIMESTAMP_SKEW_SEC) {
  console.log(`[callback] timestamp-skew-reject now=${nowSec} ts=${tsNum}`);
  return [{ json: { _route: 'reject', _response: { error: 'invalid_timestamp' }, _status: 401 } }];
}

// Ed25519 Signatur verifizieren (SPKI-prefix für Node crypto.verify)
let verifyOk = false;
try {
  if (publicKey && signature && timestamp && rawBody) {
    const pub = Buffer.from(publicKey, 'hex');
    const sig = Buffer.from(signature, 'hex');
    const msg = Buffer.from(timestamp + rawBody, 'utf8');
    verifyOk = crypto.verify(null, msg, { key: Buffer.concat([Buffer.from('302a300506032b6570032100', 'hex'), pub]), format: 'der', type: 'spki' }, sig);
  }
} catch (err) {
  console.log(`[callback] verify-exception ${err.message}`);
}

if (!verifyOk) {
  console.log(`[callback] sig-invalid type=${body.type} rawLen=${rawBody.length} sigLen=${signature.length}`);
  return [{ json: { _route: 'reject', _response: { error: 'invalid_signature' }, _status: 401 } }];
}

// PING — Discord Endpoint-Verifikation
if (body.type === 1) {
  console.log('[callback] ping-ok');
  return [{ json: { _route: 'pong', _response: { type: 1 }, _status: 200 } }];
}

// MESSAGE_COMPONENT (Button-Click)
if (body.type === 3) {
  const customId = body.data?.custom_id ?? '';
  const [actionRaw, prRaw] = customId.split(':');
  const action = (actionRaw ?? '').toLowerCase().trim();
  const prNumber = parseInt(prRaw ?? '', 10);
  const userId = body.member?.user?.id ?? body.user?.id ?? '';
  const interactionId = body.id ?? '';
  const interactionToken = body.token ?? '';

  if (!VALID_ACTIONS.has(action) || !Number.isFinite(prNumber) || prNumber <= 0) {
    console.log(`[callback] malformed-custom-id '${customId}'`);
    return [{ json: { _route: 'reject', _response: { type: 4, data: { content: `Unknown action \`${customId}\``, flags: 64 } }, _status: 200 } }];
  }

  console.log(`[callback] dispatch action=${action} pr=${prNumber} user=${userId} iid=${interactionId}`);

  return [{ json: {
    _route: 'dispatch',
    _response: { type: 6 },
    _status: 200,
    _dispatch: {
      action,
      pr_number: prNumber,
      user_id: userId,
      target_repo: $env.GITHUB_TARGET_REPO ?? 'EtroxTaran/ai-portal',
      interaction_id: interactionId,
      interaction_token: interactionToken
    }
  } }];
}

console.log(`[callback] unknown-type ${body.type}`);
return [{ json: { _route: 'reject', _response: { error: 'unknown_type' }, _status: 400 } }];

const item = $input.first()?.json ?? {};
const status = item.statusCode ?? item.status ?? 0;
const dispatch = $('Verify + Route').first().json._dispatch ?? {};
const ok = status >= 200 && status < 300;

console.log(`[callback] github-dispatch status=${status} ok=${ok} action=${dispatch.action} pr=${dispatch.pr_number}`);
if (!ok) {
  const errBody = typeof item.body === 'object' ? JSON.stringify(item.body).slice(0, 300) : String(item.body || '').slice(0, 300);
  console.log(`[callback] github-dispatch-error body=${errBody}`);
}

// Discord erwartet IMMER type:6 ack innerhalb 3s (sonst Interaction failed)
// Selbst bei GitHub-Fehler: ack zurück, damit der Button im Client nicht hängt.
// Fehlerzustand wird in n8n-Logs ausgewertet.
return [{ json: { _response: { type: 6 }, _status: 200, _dispatch_ok: ok, _dispatch_status: status } }];
